import React, { useEffect, useMemo, useState, useCallback } from 'react';
import { createRoot } from 'react-dom/client';
import axios from 'axios';
import { io } from 'socket.io-client';
import './style.css';

const API = 'http://localhost:5001/api';
const socket = io('http://localhost:5001');

function App() {
  const [user, setUser] = useState(null);
  const [token, setToken] = useState('');
  const [authMode, setAuthMode] = useState('login');

  const [complaints, setComplaints] = useState([]);
  const [staff, setStaff] = useState([]);
  const [message, setMessage] = useState('');

  const [filter, setFilter] = useState({
    status: 'All',
    category: 'All',
    search: ''
  });

  const [auth, setAuth] = useState({
    name: '',
    email: '',
    password: '',
    role: 'user',
    userId: '',
    location: ''
  });

  const [form, setForm] = useState({
    title: '',
    description: '',
    category: 'Electrical',
    priority: '',
    building: '',
    floor: '',
    roomNo: '',
    area: ''
  });

  const authHeaders = useMemo(() => {
    return { Authorization: `Bearer ${token}` };
  }, [token]);

  const logout = useCallback(() => {
    localStorage.clear();
    setUser(null);
    setToken('');
    setComplaints([]);
    setStaff([]);
    setMessage('');
    setAuthMode('login');
  }, []);

  const generateIdByRole = role => {
    const random = Math.floor(100 + Math.random() * 900);
    if (role === 'admin') return `ADM${random}`;
    if (role === 'staff') return `STF${random}`;
    return `STD${random}`;
  };

  const buildComplaintLocation = () => {
    return [
      form.building && `Building/Block: ${form.building}`,
      form.floor && `Floor: ${form.floor}`,
      form.roomNo && `Room No/Lab No: ${form.roomNo}`,
      form.area && `Area/Landmark: ${form.area}`
    ]
      .filter(Boolean)
      .join(', ');
  };

  const loadData = useCallback(async () => {
    if (!token || !user) return;

    try {
      const res = await axios.get(`${API}/complaints`, {
        headers: authHeaders
      });

      setComplaints(res.data);

      if (user.role === 'admin') {
        const staffRes = await axios.get(`${API}/users/staff`, {
          headers: authHeaders
        });
        setStaff(staffRes.data);
      }
    } catch (e) {
      const msg = e.response?.data?.message || 'Failed to load data';
      setMessage(msg);

      if (e.response?.status === 401 || msg.toLowerCase().includes('invalid token')) {
        logout();
      }
    }
  }, [token, user, authHeaders, logout]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  useEffect(() => {
    const handleUpdate = () => loadData();
    socket.on('complaintsUpdated', handleUpdate);

    return () => {
      socket.off('complaintsUpdated', handleUpdate);
    };
  }, [loadData]);

  async function submitAuth(e) {
    e.preventDefault();

    try {
      if (authMode === 'register') {
        if (!auth.name || !auth.email || !auth.password || !auth.role || !auth.userId || !auth.location) {
          setMessage('Please fill all registration fields.');
          return;
        }

        await axios.post(`${API}/auth/signup`, auth);

        setMessage('Registration successful. Please login now.');
        setAuthMode('login');

        setAuth({
          name: '',
          email: auth.email,
          password: '',
          role: auth.role,
          userId: auth.userId,
          location: auth.location
        });

        return;
      }

      if (!auth.email || !auth.userId || !auth.password) {
        setMessage('Please enter email, ID and password.');
        return;
      }

      const res = await axios.post(`${API}/auth/login`, {
        email: auth.email,
        userId: auth.userId,
        password: auth.password
      });

      setToken(res.data.token);
      setUser(res.data.user);
      setMessage('Login successful');
    } catch (e) {
      setMessage(e.response?.data?.message || 'Authentication failed');
    }
  }

  async function createComplaint(e) {
    e.preventDefault();

    const location = buildComplaintLocation();

    if (!form.title || !form.description || !form.building || !form.floor || !form.roomNo) {
      setMessage('Please enter title, description, building/block, floor and room number.');
      return;
    }

    try {
      await axios.post(
        `${API}/complaints`,
        {
          title: form.title,
          description: form.description,
          category: form.category,
          priority: form.priority,
          location
        },
        { headers: authHeaders }
      );

      setForm({
        title: '',
        description: '',
        category: 'Electrical',
        priority: '',
        building: '',
        floor: '',
        roomNo: '',
        area: ''
      });

      setMessage('Complaint created successfully');
      loadData();
    } catch (e) {
      setMessage(e.response?.data?.message || 'Failed to create complaint');
    }
  }

  async function assignComplaint(id, staffId) {
    if (!staffId) return;

    try {
      await axios.put(
        `${API}/complaints/${id}/assign`,
        { staffId },
        { headers: authHeaders }
      );
      setMessage('Complaint assigned successfully');
      loadData();
    } catch (e) {
      setMessage(e.response?.data?.message || 'Failed to assign complaint');
    }
  }

  async function updateStatus(id, status) {
    try {
      await axios.put(
        `${API}/complaints/${id}/status`,
        { status },
        { headers: authHeaders }
      );
      setMessage('Status updated successfully');
      loadData();
    } catch (e) {
      setMessage(e.response?.data?.message || 'Failed to update status');
    }
  }

  async function deleteComplaint(id) {
    if (!window.confirm('Are you sure you want to delete this complaint?')) return;

    try {
      await axios.delete(`${API}/complaints/${id}`, {
        headers: authHeaders
      });
      setMessage('Complaint deleted successfully');
      loadData();
    } catch (e) {
      setMessage(e.response?.data?.message || 'Failed to delete complaint');
    }
  }

  const filtered = useMemo(() => {
    return complaints.filter(c => {
      const title = c.title || '';
      const location = c.location || '';
      const createdById = c.createdById || '';

      return (
        (filter.status === 'All' || c.status === filter.status) &&
        (filter.category === 'All' || c.category === filter.category) &&
        (
          title.toLowerCase().includes(filter.search.toLowerCase()) ||
          location.toLowerCase().includes(filter.search.toLowerCase()) ||
          createdById.toLowerCase().includes(filter.search.toLowerCase())
        )
      );
    });
  }, [complaints, filter]);

  const stats = {
    total: complaints.length,
    open: complaints.filter(c => c.status === 'Open').length,
    progress: complaints.filter(c => c.status === 'In Progress').length,
    resolved: complaints.filter(c => c.status === 'Resolved').length
  };

  if (!user) {
    return (
      <div className="loginPage">
        <div className="authCard">
          <h1>Smart Complaint Tracker</h1>
          <p>Campus / Society Issue Tracking System</p>

          <div className="demoBox">
            <b>Demo Logins:</b>
            <br />
            Admin: admin@test.com / ADM001 / 123456
            <br />
            Staff: staff@test.com / STF001 / 123456
            <br />
            Student: student@test.com / STD001 / 123456
          </div>

          <h2>{authMode === 'login' ? 'Login' : 'Register'}</h2>

          <form onSubmit={submitAuth}>
            {authMode === 'register' && (
              <>
                <input
                  placeholder="Full Name"
                  value={auth.name}
                  onChange={e => setAuth({ ...auth, name: e.target.value })}
                />

                <select
                  value={auth.role}
                  onChange={e => {
                    const role = e.target.value;
                    setAuth({
                      ...auth,
                      role,
                      userId: generateIdByRole(role)
                    });
                  }}
                >
                  <option value="user">Student / User</option>
                  <option value="staff">Staff</option>
                  <option value="admin">Admin</option>
                </select>

                <input
                  placeholder={
                    auth.role === 'admin'
                      ? 'Admin ID'
                      : auth.role === 'staff'
                      ? 'Staff ID'
                      : 'Student ID'
                  }
                  value={auth.userId}
                  onChange={e => setAuth({ ...auth, userId: e.target.value })}
                />

                <input
                  placeholder="Registered Location / Department"
                  value={auth.location}
                  onChange={e => setAuth({ ...auth, location: e.target.value })}
                />
              </>
            )}

            <input
              placeholder="Email"
              value={auth.email}
              onChange={e => setAuth({ ...auth, email: e.target.value })}
            />

            {authMode === 'login' && (
              <input
                placeholder="Student ID / Staff ID / Admin ID"
                value={auth.userId}
                onChange={e => setAuth({ ...auth, userId: e.target.value })}
              />
            )}

            <input
              type="password"
              placeholder="Password"
              value={auth.password}
              onChange={e => setAuth({ ...auth, password: e.target.value })}
            />

            <button>{authMode === 'login' ? 'Login' : 'Register'}</button>
          </form>

          <button
            className="linkBtn"
            onClick={() => {
              setMessage('');
              setAuthMode(authMode === 'login' ? 'register' : 'login');
              setAuth({
                name: '',
                email: '',
                password: '',
                role: 'user',
                userId: '',
                location: ''
              });
            }}
          >
            {authMode === 'login'
              ? 'New user? Register here'
              : 'Already registered? Login here'}
          </button>

          {message && <p className="msg">{message}</p>}
        </div>
      </div>
    );
  }

  return (
    <div>
      <nav>
        <h2>Smart Complaint Tracker</h2>
        <span>
          {user.name} ({user.role}) | ID: {user.userId}
        </span>
        <button onClick={logout}>Logout</button>
      </nav>

      <main>
        <section className="stats">
          <div><b>{stats.total}</b><span>Total</span></div>
          <div><b>{stats.open}</b><span>Open</span></div>
          <div><b>{stats.progress}</b><span>In Progress</span></div>
          <div><b>{stats.resolved}</b><span>Resolved</span></div>
        </section>

        {message && <p className="msg">{message}</p>}

        {(user.role === 'user' || user.role === 'student') && (
          <section className="panel">
            <h3>Raise Complaint</h3>

            <div className="profileBox">
              <b>Student Details:</b>
              <br />
              Name: {user.name}
              <br />
              Student ID: {user.userId}
              <br />
              Registered Location: {user.location}
            </div>

            <form className="gridForm" onSubmit={createComplaint}>
              <input placeholder="Title" value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} />

              <select value={form.category} onChange={e => setForm({ ...form, category: e.target.value })}>
                {['Electrical', 'Plumbing', 'Internet', 'Cleaning', 'Furniture', 'Security'].map(x => (
                  <option key={x}>{x}</option>
                ))}
              </select>

              <select value={form.priority} onChange={e => setForm({ ...form, priority: e.target.value })}>
                <option value="">Auto Priority</option>
                <option>Low</option>
                <option>Medium</option>
                <option>High</option>
              </select>

              <input placeholder="Building / Block No" value={form.building} onChange={e => setForm({ ...form, building: e.target.value })} />
              <input placeholder="Floor" value={form.floor} onChange={e => setForm({ ...form, floor: e.target.value })} />
              <input placeholder="Room No / Lab No" value={form.roomNo} onChange={e => setForm({ ...form, roomNo: e.target.value })} />
              <input placeholder="Area / Landmark" value={form.area} onChange={e => setForm({ ...form, area: e.target.value })} />

              <textarea placeholder="Description" value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} />

              <button>Create Complaint</button>
            </form>
          </section>
        )}

        <section className="panel">
          <h3>
            {user.role === 'admin'
              ? 'Admin Complaint Dashboard'
              : user.role === 'staff'
              ? 'Staff Assigned Complaints'
              : 'My Complaint Dashboard'}{' '}
            <span className="live">● Live</span>
          </h3>

          <div className="filters">
            <input
              placeholder="Search by title/location/student ID"
              value={filter.search}
              onChange={e => setFilter({ ...filter, search: e.target.value })}
            />

            <select value={filter.status} onChange={e => setFilter({ ...filter, status: e.target.value })}>
              <option>All</option>
              <option>Open</option>
              <option>In Progress</option>
              <option>Resolved</option>
            </select>

            <select value={filter.category} onChange={e => setFilter({ ...filter, category: e.target.value })}>
              <option>All</option>
              <option>Electrical</option>
              <option>Plumbing</option>
              <option>Internet</option>
              <option>Cleaning</option>
              <option>Furniture</option>
              <option>Security</option>
            </select>
          </div>

          <div className="cards">
            {filtered.length === 0 && <p>No complaints found.</p>}

            {filtered.map(c => (
              <div className="card" key={c.id}>
                <div className="cardHead">
                  <h4>{c.title}</h4>
                  <span className={`badge ${String(c.status || '').replace(' ', '')}`}>
                    {c.status}
                  </span>
                </div>

                <p>{c.description}</p>
                <small>{c.category} • {c.priority} Priority</small>

                <div className="detailsBox">
                  <b>Complaint Location:</b> {c.location || 'N/A'}
                  <br />
                  <b>Raised By:</b> {c.createdByName || 'N/A'}
                  <br />
                  <b>Student/User ID:</b> {c.createdById || 'N/A'}
                  <br />
                  <b>Email:</b> {c.createdByEmail || 'N/A'}
                  <br />
                  <b>Registered Location:</b> {c.createdByLocation || 'N/A'}
                  <br />
                  <b>Assigned Staff:</b>{' '}
                  {c.assignedStaffName
                    ? `${c.assignedStaffName} (${c.assignedStaffId})`
                    : 'Not assigned'}
                </div>

                <div className="actions">
                  {(user.role === 'staff' || user.role === 'admin') && (
                    <select value={c.status} onChange={e => updateStatus(c.id, e.target.value)}>
                      <option>Open</option>
                      <option>In Progress</option>
                      <option>Resolved</option>
                    </select>
                  )}

                  {user.role === 'admin' && (
                    <select value={c.assignedTo || ''} onChange={e => assignComplaint(c.id, e.target.value)}>
                      <option value="">Assign Staff</option>
                      {staff.map(s => (
                        <option key={s._id} value={s._id}>
                          {s.name} - {s.userId}
                        </option>
                      ))}
                    </select>
                  )}

                  {user.role === 'admin' && (
                    <button className="danger" onClick={() => deleteComplaint(c.id)}>
                      Delete
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </section>
      </main>
    </div>
  );
}

createRoot(document.getElementById('root')).render(<App />);
